public class OrderSummary {
    public static void main(String[] args) {
        // Order data
        String customerName = "Aisha Khan";
        int itemCount = 3;
        double unitPrice = 599.99;
        final double TAX_RATE = 18.0;
        final double SHIPPING_FEE = 50.0;

        // Calculations
        double subtotal = itemCount * unitPrice;
        double taxAmount = subtotal * (TAX_RATE / 100);
        double total = subtotal + taxAmount + SHIPPING_FEE;

        // Output
        System.out.println("========================================");
        System.out.println("            ORDER SUMMARY");
        System.out.println("========================================");
        System.out.println("Customer: " + customerName);
        System.out.println("Items:    " + itemCount);
        System.out.println("Unit Price: " + unitPrice);
        System.out.println("----------------------------------------");
        System.out.println("Subtotal:   " + subtotal);
        System.out.println("Tax (" + TAX_RATE + "%): " + taxAmount);
        System.out.println("Shipping:   " + SHIPPING_FEE);
        System.out.println("----------------------------------------");
        System.out.println("Total:      " + total);
        System.out.println("========================================");
    }
}

