public class SavingsGoal {
    public static void main(String[] args) {
        // Goal data
        double goalAmount = 500000.0;
        double currentSavings = 75000.0;
        int months = 24;
        final double ANNUAL_INTEREST_RATE = 6.5;

        // Calculations
        double remainingNeeded = goalAmount - currentSavings;
        double monthlyInterestRate = ANNUAL_INTEREST_RATE / 12 / 100;
        double estimatedInterest = currentSavings * monthlyInterestRate * months;
        double adjustedRemaining = remainingNeeded - estimatedInterest;
        double monthlySavings = adjustedRemaining / months;

        // Output
        System.out.println("=====================================");
        System.out.println("        SAVINGS GOAL PLANNER");
        System.out.println("=====================================");
        System.out.println("Goal amount:        " + goalAmount);
        System.out.println("Current savings:    " + currentSavings);
        System.out.println("Months to save:     " + months);
        System.out.println("Interest rate:      " + ANNUAL_INTEREST_RATE + "% per year");
        System.out.println("-------------------------------------");
        System.out.println("Remaining needed:   " + remainingNeeded);
        System.out.println("Est. interest gain: " + estimatedInterest);
        System.out.println("Monthly savings:    " + monthlySavings);
        System.out.println("=====================================");
    }
}
